				\usepackage{upgreek}
				\setlength{\oddsidemargin}{-69pt}
				\begin{document}$${{{\rm{Replication\; coefficient}}}}=\frac{{{{\rm{Viral\; copies}}}}({{{\rm{standard\; culture}}}})}{{{{\rm{Viral\; copies}}}}({{{\rm{inactivated\; culture}}}})}$$\end{document}Replication coefficient=Viral copies(standard culture)Viral copies(inactivated culture)
